import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class AnnotationRuleArraySyntaxAnnotationTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given an array syntax annotation on same line as annotated construct then report and autocorrect`() {
        val code =
            """
            @[JvmStatic Provides] fun foo() = 42
            """.trimIndent()
        val formattedCode =
            """
            @[JvmStatic Provides]
            fun foo() = 42
            """.trimIndent()

        annotationRuleAssertThat(code)
            .hasLintViolation(1, 1, "Annotation must be placed on separate line")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an array syntax annotation containing an annotation with parameter on same line as annotated construct then report and autocorrect without wrapping the entries`() {
        val code =
            """
            @[Suppress("DEPRECATION") Provides] fun foo() = 42
            """.trimIndent()
        val formattedCode =
            """
            @[Suppress("DEPRECATION") Provides]
            fun foo() = 42
            """.trimIndent()

        annotationRuleAssertThat(code)
            .hasLintViolation(1, 1, "Annotation must be placed on separate line")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a use-site target array syntax annotation on same line as annotated construct then report and autocorrect`() {
        val code =
            """
            class Foo {
                @set:[Inject VisibleForTesting] public var collaborator: Collaborator
            }
            """.trimIndent()
        val formattedCode =
            """
            class Foo {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()

        annotationRuleAssertThat(code)
            .hasLintViolation(2, 5, "Annotation must be placed on separate line")
            .isFormattedAs(formattedCode)
    }
}
"}

